INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 301, "", 10, "", "", "なかよしX…\nあれは実に\n浪漫の結晶だった…", "", "", 13010008);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 301, "", "", "", "", 1, "", "", 13010009);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 301, "", 10, "", "", "あのイノベーション\nから得た刺激は形に\n遺しておくべきだ…", "", "", 13010010);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 301, "", "", "", "", 1, "", "", 13010011);
