INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 301, "", 10, "", "", "これらをリペアして\n単に組み直したとて\n模造品でしかない", "", "", 13010017);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 301, "", "", "", "", 1, "", "", 13010018);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (3, 111031, 301, 1, 0, "", "", "nyx_103_yuni_03", "nyx_103_yuni_04", 0.2, 13010019);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 301, "", 10, "", "", "独自の改修を施すぞ\n機体の縮小化そして\n各種機能を改良だ", "", "", 13010020);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 301, "", "", "", "", 1, "", "", 13010021);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (3, 111031, 301, "", 1, "", "", "cmn_pose02_def_N", "", 0.2, 13010022);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 301, "", 10, "", "", "ふむ、すなわち\nたい焼きに麦しゅわ\nだが…", "", "", 13010023);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 301, "", "", "", "", "", "", "", 13010024);
