INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 301, "", 10, "", "", "いや、そもそもなぜ\nたい焼き麦しゅわが\n組み込まれていたか", "", "", 13010027);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 301, "", "", "", "", 1, "", "", 13010028);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 301, "", 10, "", "", "…理解に苦しむな\nまずそこから考える\n必要がありそうだ", "", "", 13010029);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 301, "", "", "", "", 1, "", "", 13010030);
