INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 13020011, 302, "", "", "", "", "", "", "", 13020014);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 302, "", 10, "", "", "いかんいかん\n資材の山に埋もれて\nしまうところだった", "", "", 13020015);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 302, "", "", "", "", "", "", "", 13020016);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (3, 2, 302, 1, 0, "", "", "nyx_302_yuni_02", "NoItem", 0.2, 13020017);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (3, 111031, 302, 1, 0, 0.2, "", "nyx_302_yuni_02", "nyx_idle_normal", 0.2, 13020018);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 302, "", 10, "", "", "だが怪我の功名、\n探していた部品を\n偶然にも発見できた", "", "", 13020019);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (93, 5, 302, "", "", "", "", "", "", "", 13020020);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (4, 111031, 302, "", "", "", "", 0, "", "", 13020021);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (3, 111031, 302, "", 1, "", "", "nyx_cmn_03", "", 0.2, 13020022);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 302, "", 10, "", "", "ふむ…これは僥倖\nかくなる上は再び\n潜航してみるか…", "", "", 13020023);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 302, "", "", "", "", "", "", "", 13020024);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (3, 111031, 302, "", 1, "", "", "nyx_301_yuni_01", "", 0.2, 13020025);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 302, "", 10, "", "", "存外意義あるものだ\n資材ダイビングとか\nいう新種の探索行は", "", "", 13020026);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 302, "", "", "", "", 1, "", "", 13020027);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 302, "", 10, "", "", "まあ万一溺れたとて\n後輩たちの誰ぞが\nきっと気付くだろう", "", "", 13020028);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 302, "", "", "", "", 1, "", "", 13020029);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (3, 111031, 302, 1, 0, "", "", "nyx_302_yuni_03", "nyx_302_yuni_04", 0.2, 13020030);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 302, "", 10, "", "", "是非もなし\nいざ往かん！", "", "", 13020031);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 302, "", "", "", "", 1, "", "", 13020032);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (93, 1.5, 302, "", "", "", "", "", "", "", 13020033);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 302, "", 10, "", "", "む。奥に入りすぎた\nこれは…出られぬ！\n誰かー！　誰か―！", "", "", 13020034);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 302, "", "", "", "", "", "", "", 13020035);
