INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 303, "", 10, "", "", "ふふふ…我ながら\n納得の出来栄え…", "", "", 13030008);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 303, "", "", "", "", "", "", "", 13030009);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 303, "", 10, "", "", "外観の完成度も\nさることながら\n特筆すべきは機能だ", "", "", 13030010);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 303, "", "", "", "", "", "", "", 13030011);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (3, 111031, 303, "", 1, "", "", "nyx_303_yuni_03", "", 0.2, 13030012);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 303, "", 10, "", "", "試しに動作試験を\nしてみるとしよう", "", "", 13030013);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 303, "", "", "", "", "", "", "", 13030014);
