INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (3, 111031, 303, "", 1, "", "", "nyx_303_yuni_07", "", 0.2, 13030017);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 303, "", 10, "", "", "ふむ…\n表情映写の動作に\n問題はないようだ", "", "", 13030018);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 303, "", "", "", "", "", "", "", 13030019);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (3, 111031, 303, 1, 0, 0.2, "", "nyx_303_yuni_09", "nyx_303_yuni_04", 0.2, 13030020);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 303, "", 10, "", "", "次はいずれの機能を\n試してみるか…", "", "", 13030021);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, 0, 303, "", "", "", "", "", "", "", 13030022);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (93, 0.5, 303, "", "", "", "", "", "", "", 13030023);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, 111031, 303, "", 10, "", "", "とりあえず適当な\nスイッチを…おっと\nこのボタンはいかん", "", "", 13030024);
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (93, 1.5, 303, "", "", "", "", "", "", "", 13030025);
